import OpenAI from "openai";

const client = new OpenAI();

const userMessage = process.env.USER_MESSAGE;
const metadata = process.env.THREAD_METADATA ? JSON.parse(process.env.THREAD_METADATA) : undefined;

const createParams = {};

if (userMessage) {
  createParams.messages = [
    { role: "user", content: userMessage },
  ];
}

if (metadata) {
  createParams.metadata = metadata;
}

const thread = await client.beta.threads.create(createParams);

console.log(JSON.stringify({
  threadId: thread.id,
  createdAt: thread.created_at,
  metadata: thread.metadata,
}, null, 2));
